{"code": "import json
import re
from collections import defaultdict

# Read businesses that accept credit cards
business_file = locals()['var_functions.query_db:8']
with open(business_file, 'r') as f:
    businesses = json.load(f)

# Read all reviews
reviews_file = locals()['var_functions.query_db:10']
with open(reviews_file, 'r') as f:
    reviews = json.load(f)

# Parse categories from business descriptions
def extract_categories(description):
    # Look for category lists in description
    if not description:
        return []

    # Pattern 1: "services in X, Y, and Z"
    match = re.search(r'(?:services? in|category of|options in|offerings in|fields of|specializes? in|offering in) (.+?)(?:\.|, [Ll]ocated at|$)', description)
    if match:
        cats_text = match.group(1)
        # Split by comma and 'and', then clean up
        cats = re.split(r',\s*|\sand\s', cats_text)
        # Handle "A & B" format
        cats = [re.split(r'\s*&\s*', cat.strip()) for cat in cats]
        # Flatten the list
        cats = [item.strip() for sublist in cats for item in sublist]
        # Remove empty and common words
        cats = [cat for cat in cats if cat and cat.lower() not in ['and', 'in', 'of', 'to', 'a', 'services', 'category']]
        return cats
    return []

# Extract categories from each business
business_categories = {}
business_id_mapping = {}
for business in businesses:
    business_id = business['business_id'].replace('businessid_', 'businessref_')
    business_id_mapping[business_id] = business
    categories = extract_categories(business.get('description', ''))
    if categories:
        business_categories[business_id] = categories[0]  # Take first category as primary
    else:
        business_categories[business_id] = 'Unknown'

# Map categories to business counts
category_data = defaultdict(list)
for business_id, category in business_categories.items():
    category_data[category].append(business_id)

# Join reviews with businesses and calculate ratings
business_ratings = defaultdict(list)
for review in reviews:
    business_ref = review['business_ref']
    if business_ref in business_categories:
        try:
            rating = float(review['rating'])
            business_ratings[business_ref].append(rating)
        except (ValueError, TypeError):
            continue

# Calculate business-level average ratings
business_avg_rating = {}
for business_ref, ratings in business_ratings.items():
    if ratings:
        business_avg_rating[business_ref] = sum(ratings) / len(ratings)

# Calculate category-level statistics
category_stats = {}
for category, business_ids in category_data.items():
    if category == 'Unknown':
        continue

    # Filter to businesses that accept credit cards and have reviews
    valid_businesses = []
    ratings = []
    for business_id in business_ids:
        if business_id in business_avg_rating:
            valid_businesses.append(business_id)
            ratings.append(business_avg_rating[business_id])

    if valid_businesses:
        category_stats[category] = {
            'business_count': len(valid_businesses),
            'avg_rating': sum(ratings) / len(ratings) if ratings else 0,
            'business_ids': valid_businesses
        }

# Find category with most businesses
if category_stats:
    top_category = max(category_stats.items(), key=lambda x: x[1]['business_count'])

    result = {
        'top_category': top_category[0],
        'business_count': top_category[1]['business_count'],
        'avg_rating': round(top_category[1]['avg_rating'], 2)
    }
else:
    result = {
        'top_category': 'Unknown',
        'business_count': 0,
        'avg_rating': 0.0
    }

print("__RESULT__:")
print(json.dumps(result, indent=2))"}
